tool.command:
@CMD_UNZIP_ZARR@
mkdir -p output_dir &&
## Determine the SpatialData directory name SDATA_DIR=\$(find . -maxdepth 1 -name "*.zarr" -type d | head -n 1) &&
## Run segmentation sopa segmentation #if $method.method_name == 'cellpose' cellpose "\${SDATA_DIR}" #for $channel in str($method.channels).split(',') --channels '$channel' #end for --diameter $method.diameter #if str($method.model_type) != '' --model-type '$method.model_type' #end if #if str($method.pretrained_model) != '' --pretrained-model '$method.pretrained_model' #end if --min-area $method.min_area --flow-threshold $method.flow_threshold --cellprob-threshold $method.cellprob_threshold #if $method.advanced.gaussian_sigma --gaussian-sigma $method.advanced.gaussian_sigma #end if #if $method.advanced.clip_limit --clip-limit $method.advanced.clip_limit #end if #if str($method.advanced.resample) == 'yes' ## resample is True by default, only pass flag to disable it #else --method-kwargs '{"resample": False}' #end if #else if $method.method_name == 'baysor' baysor "\${SDATA_DIR}" #if $method.config_source.source == 'file' --config '$method.config_source.config_file' #else --config '$method.config_source.config_text' #end if #if str($method.prior_shapes_key) != '' --prior-shapes-key '$method.prior_shapes_key' #end if #else if $method.method_name == 'generic' generic-staining "\${SDATA_DIR}" --method-name '$method.method_name_generic' #if str($method.method_kwargs) != '' --method-kwargs '$method.method_kwargs' #end if #end if &&
## Move to output directory mv "\${SDATA_DIR}" output_dir/ &&
@CMD_ZIP_ZARR@
